import React, { Component } from 'react'

import PersonalData from './components/PersonalData'
import Contact from './components/Contact'
import Education from './components/Education'
import Language from './components/Language'
import Tool from './components/Tool'
import Qualification from './components/Qualification'
import Hobby from './components/Hobby'
import TargetJob from './components/TargetJob'
import Certification from './components/Certification'

class App extends Component {
  state = {
    language: 'eng',
    nav: false
  }

  componentDidMount = () => {
    window.addEventListener('scroll', this.handleScroll)
  }

  componentWillUnmount = () => {
    window.removeEventListener('scroll', this.handleScroll)
  }

  handleScroll = () => {
    if (window.scrollY > 230) {
      this.setState({ nav: true })
    } else {
      this.setState({ nav: false })
    }
  }

  render() {
    return (
      <div>
        <section className="section">
          <div className="container">
            {/* header */}
            <div className="columns">
              <div className="column has-text-centered">
                <h1 className="title is-1">Resume</h1>
                <p className="subtitle is-5" style={{ paddingLeft: 100 }}>
                  Sumet Phongphila
                </p>
              </div>
            </div>
            <hr />

            {/* nav */}
            <div className="level">
              <div className="level-item buttons has-addons">
                <span
                  className="button"
                  onClick={() => this.setState({ language: 'eng' })}
                >
                  Eng
                </span>
                <span
                  className="button"
                  onClick={() => this.setState({ language: 'thai' })}
                >
                  Thai
                </span>
              </div>
            </div>

            {/* layout */}
            <div className="columns is-centered">
              <div className="column is-6">
                <PersonalData lang={this.state.language} />
              </div>
            </div>

            <div className="columns is-centered">
              <div className="column is-5">
                <div>
                  <Contact lang={this.state.language} />
                </div>
                <div style={{ marginTop: '1.25rem' }}>
                  <Qualification lang={this.state.language} />
                </div>
                <div style={{ marginTop: '1.25rem' }}>
                  <Hobby lang={this.state.language} />
                </div>
                <div style={{ marginTop: '1.25rem' }}>
                  <TargetJob lang={this.state.language} />
                </div>
              </div>
              <div className="column is-5">
                <div>
                  <Education lang={this.state.language} />
                </div>
                <div style={{ marginTop: '1.25rem' }}>
                  <Certification lang={this.state.language} />
                </div>
              </div>
            </div>

            <div className="columns is-centered">
              <div className="column is-9">
                <Language lang={this.state.language} />
              </div>
            </div>

            <div className="columns is-centered">
              <div className="column is-9">
                <Tool lang={this.state.language} />
              </div>
            </div>
          </div>
        </section>

        {/* footer */}
        <footer className="footer">
          <div className="content has-text-centered">
            <a
              className="has-text-black"
              href="https://github.com/sumetph"
              target="_black"
            >
              <span className="icon is-large">
                <i className="fab fa-github-alt fa-2x" />
                <p style={{ marginLeft: '1rem' }}>Github</p>
              </span>
            </a>
          </div>
        </footer>

        {/* nav bottom */}
        <div style={{ position: 'fixed', bottom: 0, right: 0, margin: 15 }}>
          {this.state.nav ? (
            <div className="level">
              <div className="level-item buttons has-addons">
                <span
                  className="button"
                  onClick={() => this.setState({ language: 'eng' })}
                >
                  Eng
                </span>
                <span
                  className="button"
                  onClick={() => this.setState({ language: 'thai' })}
                >
                  Thai
                </span>
              </div>
            </div>
          ) : null}
        </div>
      </div>
    )
  }
}

export default App
